"""
Advanced MongoDB Data Filtering Service - Secure Implementation

Provides complex query capabilities using MongoDB's native query operators
instead of dangerous $where/server-side JavaScript execution.
"""

import re
from datetime import datetime
from typing import Any, Optional

from pymongo import MongoClient
from pymongo.collection import Collection
from pymongo.errors import OperationFailure


# ---------------------------------------------------------------------------
# Whitelist of allowed MongoDB query operators
# ---------------------------------------------------------------------------
ALLOWED_OPERATORS = {
    # Comparison
    "$eq", "$ne", "$gt", "$gte", "$lt", "$lte", "$in", "$nin",
    # Logical
    "$and", "$or", "$nor", "$not",
    # Element
    "$exists", "$type",
    # Array
    "$all", "$elemMatch", "$size",
    # Evaluation (safe subset)
    "$regex", "$mod",
    # Geospatial (if needed)
    "$geoWithin", "$geoIntersects", "$near", "$nearSphere",
}

# Operators that are BLOCKED because they allow code execution
BLOCKED_OPERATORS = {
    "$where",
    "$accumulator",
    "$function",
    "$expr",  # Can be safe but restrict for defense-in-depth
}

ALLOWED_FIELD_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_.]*$")

MAX_QUERY_DEPTH = 10
MAX_RESULTS = 1000


class QueryValidationError(Exception):
    """Raised when a user-provided query fails validation."""
    pass


class SecureFilterService:
    """
    Advanced data filtering service that translates user filter
    specifications into safe MongoDB queries.
    """

    def __init__(
        self,
        connection_string: str = "mongodb://localhost:27017",
        database_name: str = "app_database",
        allowed_collections: Optional[set[str]] = None,
    ):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        self.allowed_collections = allowed_collections or set()

    # ------------------------------------------------------------------
    # Query validation
    # ------------------------------------------------------------------

    def _validate_field_name(self, field: str) -> None:
        """Ensure field names don't contain injection payloads."""
        if not isinstance(field, str):
            raise QueryValidationError(f"Field name must be a string, got {type(field)}")
        if not ALLOWED_FIELD_PATTERN.match(field):
            raise QueryValidationError(
                f"Invalid field name: '{field}'. "
                "Field names must start with a letter or underscore and "
                "contain only alphanumeric characters, underscores, or dots."
            )

    def _validate_value(self, value: Any) -> None:
        """Ensure values are safe primitive types or allowed structures."""
        if value is None:
            return
        if isinstance(value, (bool, int, float, str, datetime)):
            return
        if isinstance(value, list):
            for item in value:
                self._validate_value(item)
            return
        if isinstance(value, dict):
            # Dicts in values are allowed only if they contain allowed operators
            self._validate_query(value, _depth=0)
            return
        raise QueryValidationError(
            f"Unsupported value type: {type(value).__name__}"
        )

    def _validate_query(self, query: dict, _depth: int = 0) -> None:
        """
        Recursively validate that a query dict contains only allowed
        operators and safe field names / values.
        """
        if _depth > MAX_QUERY_DEPTH:
            raise QueryValidationError("Query exceeds maximum nesting depth")

        if not isinstance(query, dict):
            raise QueryValidationError("Query must be a dictionary")

        for key, value in query.items():
            # Check for blocked operators
            if key in BLOCKED_OPERATORS:
                raise QueryValidationError(
                    f"Operator '{key}' is not allowed. "
                    "Server-side JavaScript execution is disabled for security."
                )

            if key.startswith("$"):
                # It's an operator – must be in the whitelist
                if key not in ALLOWED_OPERATORS:
                    raise QueryValidationError(
                        f"Operator '{key}' is not in the allowed operator list."
                    )
                # Recurse into operator value
                if isinstance(value, dict):
                    self._validate_query(value, _depth + 1)
                elif isinstance(value, list):
                    for item in value:
                        if isinstance(item, dict):
                            self._validate_query(item, _depth + 1)
                        else:
                            self._validate_value(item)
                else:
                    self._validate_value(value)
            else:
                # It's a field name
                self._validate_field_name(key)
                if isinstance(value, dict):
                    self._validate_query(value, _depth + 1)
                elif isinstance(value, list):
                    for item in value:
                        if isinstance(item, dict):
                            self._validate_query(item, _depth + 1)
                        else:
                            self._validate_value(item)
                else:
                    self._validate_value(value)

    def _validate_collection(self, collection_name: str) -> None:
        if self.allowed_collections and collection_name not in self.allowed_collections:
            raise QueryValidationError(
                f"Collection '{collection_name}' is not in the allowed list."
            )

    # ------------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------------

    def filter_documents(
        self,
        collection_name: str,
        user_filter: dict,
        projection: Optional[dict] = None,
        sort: Optional[list[tuple[str, int]]] = None,
        limit: int = 100,
        skip: int = 0,
    ) -> list[dict]:
        """
        Execute a validated filter query against a MongoDB collection.

        Parameters
        ----------
        collection_name : str
            Target collection.
        user_filter : dict
            MongoDB query document (validated before execution).
        projection : dict, optional
            Fields to include/exclude.
        sort : list of (field, direction) tuples, optional
        limit : int
            Max documents to return (capped at MAX_RESULTS).
        skip : int
            Number of documents to skip.

        Returns
        -------
        list[dict]
            Matching documents.
        """
        # Validate everything before touching the database
        self._validate_collection(collection_name)
        self._validate_query(user_filter)

        if projection:
            for field in projection:
                self._validate_field_name(field)

        if sort:
            for field, direction in sort:
                self._validate_field_name(field)
                if direction not in (1, -1):
                    raise QueryValidationError("Sort direction must be 1 or -1")

        limit = min(max(1, limit), MAX_RESULTS)
        skip = max(0, skip)

        collection: Collection = self.db[collection_name]

        try:
            cursor = collection.find(
                filter=user_filter,
                projection=projection,
            ).skip(skip).limit(limit)

            if sort:
                cursor = cursor.sort(sort)

            return list(cursor)

        except OperationFailure as exc:
            raise QueryValidationError(f"MongoDB rejected the query: {exc}") from exc

    def count_documents(
        self,
        collection_name: str,
        user_filter: dict,
    ) -> int:
        """Return count of documents matching the validated filter."""
        self._validate_collection(collection_name)
        self._validate_query(user_filter)

        collection: Collection = self.db[collection_name]
        try:
            return collection.count_documents(user_filter)
        except OperationFailure as exc:
            raise QueryValidationError(f"MongoDB rejected the query: {exc}") from exc

    def aggregate(
        self,
        collection_name: str,
        match_filter: dict,
        group_by: str,
        aggregations: dict[str, tuple[str, str]],
        limit: int = 100,
    ) -> list[dict]:
        """
        Safe aggregation: $match → $group → $limit.

        Parameters
        ----------
        match_filter : dict
            Validated filter for the $match stage.
        group_by : str
            Field to group by.
        aggregations : dict
            Mapping of output_field -> (operator, source_field).
            e.g. {"total_sales": ("$sum", "amount")}
        """
        self._validate_collection(collection_name)
        self._validate_query(match_filter)
        self._validate_field_name(group_by)

        allowed_accumulators = {"$sum", "$avg", "$min", "$max", "$first", "$last", "$count"}
        group_stage: dict[str, Any] = {"_id": f"${group_by}"}

        for output_field, (operator, source_field) in aggregations.items():
            self._validate_field_name(output_field)
            if operator not in allowed_accumulators:
                raise QueryValidationError(f"Accumulator '{operator}' is not allowed")
            if operator == "$count":
                group_stage[output_field] = {operator: {}}
            else:
                self._validate_field_name(source_field)
                group_stage[output_field] = {operator: f"${source_field}"}

        pipeline = [
            {"$match": match_filter},
            {"$group": group_stage},
            {"$limit": min(max(1, limit), MAX_RESULTS)},
        ]

        collection: Collection = self.db[collection_name]
        try:
            return list(collection.aggregate(pipeline))
        except OperationFailure as exc:
            raise QueryValidationError(f"MongoDB rejected the pipeline: {exc}") from exc

    # ------------------------------------------------------------------
    # Convenience: build filters from a simplified DSL
    # ------------------------------------------------------------------

    @staticmethod
    def build_filter_from_rules(rules: list[dict]) -> dict:
        """
        Convert a list of simple rule dicts into a MongoDB query.

        Each rule: {
            "field": "age",
            "operator": "gte",
            "value": 18
        }

        Supported operators: eq, ne, gt, gte, lt, lte, in, nin,
                             exists, regex, size, mod
        """
        operator_map = {
            "eq": "$eq",
            "ne": "$ne",
            "gt": "$gt",
            "gte": "$gte",
            "lt": "$lt",
            "lte": "$lte",
            "in": "$in",
            "nin": "$nin",
            "exists": "$exists",
            "regex": "$regex",
            "size": "$size",
            "mod": "$mod",
        }

        conditions = []
        for rule in rules:
            field = rule.get("field")
            op = rule.get("operator")
            value = rule.get("value")

            if op not in operator_map:
                raise QueryValidationError(f"Unknown rule operator: '{op}'")

            mongo_op = operator_map[op]

            if op == "eq":
                conditions.append({field: value})
            else:
                conditions.append({field: {mongo_op: value}})

        if len(conditions) == 1:
            return conditions[0]
        return {"$and": conditions}

    def close(self) -> None:
        self.client.close()


